There is a miscompilation issue report in ConstraintElimination: 

clang at -O2/3 produced the wrong code.

Bisected to 98e016d99732dc8fef8cfd61d6ce1edd042309a1, which was committed y @fhahn 

Compiler explorer: https://godbolt.org/z/6W5ExaWPM

```console
% cat a.c 
int printf(const char *, ...);
int a, b, c;
long d;
unsigned short e;
short f = 5;
int *g = &a;
short(h)(short j, short k) { return j % k; }
int *l() {
  long m = 0;
  int i = 0;
  for (; i < 1; --d)
    for (; m <= 7; m++) {
      int n;
      for (; i < 6; i++)
        ;
      e = h(f++, 4);
      *g = !e;
      n = m == e;
      if (n)
        return &c;
    }
  return &b;
}
int main() {
  l();
  printf("%d\n", a);
}
%
% clang -O0 a.c && ./a.out
1
% clang -O2 a.c && ./a.out
0
%
```

The maintainers proposed the following patch to fix the issue:

commit 4acc357a3700e6bc7afe3f6393d423c3d8b02d7d
Author: Yingwei Zheng <dtcxzyw2333@gmail.com>
Date:   Thu Nov 2 23:38:05 2023 +0800

    [ConstraintElim] Add missing check to make sure the bound is loop-invariant (#70555)

    This PR adds a missing check for
    https://github.com/llvm/llvm-project/commit/e6a1657fa30c747f4412fc47f567660ebe861a9e
    to make sure the bound is loop-invariant.

    Example:
    ```
    define i32 @main() {
    entry:
      br label %for.header

    for.header:
      %ind1 = phi i64 [ %ind1.i, %for.latch ], [ 0, %entry ]
      %ind2 = phi i64 [ %ind2.i, %for.latch ], [ 5, %entry ]
      %rem = srem i64 %ind2, 4
      %cmp6 = icmp eq i64 %ind1, %rem
      br i1 %cmp6, label %exit1, label %for.latch

    for.latch:
      %ind2.i = add i64 %ind2, 1
      %ind1.i = add i64 %ind1, 1
      %cond = icmp eq i64 %ind1.i, 8
      br i1 %cond, label %exit2, label %for.header

    exit2:
      %cmp = icmp eq i64 %rem, 0
      %ret = zext i1 %cmp to i32
      ret i32 %ret

    exit1:
      ret i32 0
    }
    ```
    We cannot infer `%ind1 <u %rem` from `icmp eq i64 %ind1, %rem` in the
    loop since `%rem` is not a loop-invariant.

    Fixes #70510.

diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 37f720ec40f4..2d829ee017be 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -899,6 +899,10 @@ void State::addInfoForInductions(BasicBlock &BB) {
   else
     return;

+  // Make sure the bound B is loop-invariant.
+  if (!L->isLoopInvariant(B))
+    return;
+
   // Handle negative steps.
   if (StepOffset.isNegative()) {
     // TODO: Extend to allow steps > -1.


